// // This module implements a 16-bit shift register with parallel load capability. The shift register has the following inputs: a 16-bit data input (data_in), a load signal (load), a shift signal (shift), and a clock signal (clk). When the load signal is high, the data_in should be loaded into the register. When the shift signal is high, the data in the register should be shifted to the left by one position, with the most significant bit (MSB) shifting out. The least significant bit (LSB) should be filled with zero after shifting.
module shift_register (  
    input clk,  
    input load,  
    input shift,  
    input [15:0] data_in,  
    output reg [15:0] data_out  
);  

    always @(posedge clk) begin  
        if (load) begin  
            data_out <= data_in;  
        end else if (shift) begin  
            data_out <= {1'b0, data_out[15:1]};  
        end  
    end  
endmodule
